def solve(nums: Array[Long]): Boolean = {
  val n = nums.length
  if (n < 3) return false

  // Find p such that nums[0...p] is strictly increasing
  var p = 0
  while (p + 1 < n && nums(p) < nums(p + 1)) {
    p += 1
  }

  // Find q such that nums[p...q] is strictly decreasing
  var q = p
  while (q + 1 < n && nums(q) > nums(q + 1)) {
    q += 1
  }

  // Check if nums[q...n-1] is strictly increasing
  var i = q
  while (i + 1 < n && nums(i) < nums(i + 1)) {
    i += 1
  }

  i == n - 1
}
